def solve(arg1: dict) -> dict:
    country_data = {
        'US': {'name': 'United States', 'code': 'US'},
        'CA': {'name': 'Canada', 'code': 'CA'},
        # Add more countries as needed
    }

    device_data = {
        '12345': {'name': 'Device A', 'id': '12345'},
        # Add more devices as needed
    }

    if 'countryCode' in arg1:
        country_code = arg1['countryCode']
        if country_code in country_data:
            return {'fromDB': True, 'result': country_data[country_code]}
        else:
            return {'fromDB': True, 'result': None}

    if 'deviceId' in arg1:
        device_id = arg1['deviceId']
        if device_id in device_data:
            return {'fromDB': True, 'result': device_data[device_id]}

    return {'secured': False}
